import React from 'react'
import LeftPanel from './left'
import RightPanels from './right'
import Canvas from './canvas'
import { ARTBOARD_VIEW_MODES } from './ArtboardViewControls'
import './main.scss'

const ARTBOARD_VIEW_STORAGE_KEY = 'heronHandoff.artboardViewSettings'
const DEFAULT_THUMBNAIL_SIZES = ARTBOARD_VIEW_MODES.reduce((sizes, mode) => {
  sizes[mode.key] = mode.defaultSize
  return sizes
}, {})
const DEFAULT_ARTBOARD_VIEW_SETTINGS = {
  viewMode: 'artboard',
  thumbnailSizes: DEFAULT_THUMBNAIL_SIZES,
  hideFileName: false,
  hideResourceCount: false,
  displayAttribute: 'none',
  autoplay: 'animated',
  spacing: 'auto',
  sortDirection: 'desc',
  sortField: 'updated',
  savedViewEnabled: true
}

class Main extends React.Component {
  constructor(props) {
    super(props)
    this.state = {
      currentImageUrl: '',
      canvasData: null,
      id: '',
      // selected layer index
      currentIndex: '',
      elementData: null,
      hasElementSelected: false,
      closestComponent: null,
      siderCollapseFlag: false,
      exportIds: [],
      exportNames: [],
      slicePanelVisible: false,
      artboardViewSettings: DEFAULT_ARTBOARD_VIEW_SETTINGS
    }
  }
  handleSelectFrameOrComponent = (currentId, currentImageUrl, pageId) => {
    const { data, components, onNamesChange } = this.props
    const { id } = this.state
    if (id===currentId) return
    const currentPage = pageId ? data.document.children.find(({id}) => id===pageId) : {}
    const canvasData = (pageId ? currentPage.children : components).find(({id}) => id===currentId)
    this.setState({
      id: currentId,
      currentImageUrl,
      canvasData
    })
    onNamesChange && onNamesChange(canvasData.name, currentPage.name)
    this.handleDeselect()
  }
  getCanvasFrames = () => {
    const { data, mode, isMock } = this.props
    if (!data || !data.document || !data.document.children) return []
    const frames = []
    data.document.children.forEach(page => {
      if (!page.children) return
      page.children
        .filter(frame => frame.type === 'FRAME' && frame.visible !== false)
        .forEach((frame, index) => {
          const fileName = frame.assetFileName ? `../assets/${frame.assetFileName}` : frame.fileName ? `exports/${frame.fileName}` : `${frame.id.replace(/:/g, '-')}.png`
          frames.push({
            ...frame,
            pageId: page.id,
            pageName: page.name,
            originalIndex: frames.length,
            pageIndex: index,
            imageUrl: (mode==='local' || isMock) ?
              `${process.env.PUBLIC_URL}/data/${fileName}` :
              frame.image && frame.image.url
          })
        })
    })
    return frames
  }
  handleSelectElement = (elementData, index, closestComponent) => {
    this.setState({
      elementData,
      currentIndex: index,
      closestComponent,
      hasElementSelected: true
    })
  }
  handleGetExports = (exportIds, exportNames) => {
    this.setState({ exportIds, exportNames })
  }
  handleSlicePanelVisibleChange = slicePanelVisible => {
    this.setState({ slicePanelVisible })
  }
  handleArtboardViewChange = partialSettings => {
    this.setState(({ artboardViewSettings }) => ({
      artboardViewSettings: {
        ...artboardViewSettings,
        ...partialSettings
      }
    }))
  }
  saveArtboardViewSettings = () => {
    window.localStorage.setItem(
      ARTBOARD_VIEW_STORAGE_KEY,
      JSON.stringify(this.state.artboardViewSettings)
    )
  }
  resetArtboardViewSettings = () => {
    this.setState({
      artboardViewSettings: {
        ...DEFAULT_ARTBOARD_VIEW_SETTINGS,
        thumbnailSizes: { ...DEFAULT_THUMBNAIL_SIZES }
      }
    }, this.saveArtboardViewSettings)
  }
  loadArtboardViewSettings = () => {
    try {
      const saved = JSON.parse(window.localStorage.getItem(ARTBOARD_VIEW_STORAGE_KEY))
      if (saved) {
        this.setState({
          artboardViewSettings: {
            ...DEFAULT_ARTBOARD_VIEW_SETTINGS,
            ...saved,
            thumbnailSizes: {
              ...DEFAULT_THUMBNAIL_SIZES,
              ...(saved.thumbnailSizes || {})
            }
          }
        })
      }
    } catch (error) {
      console.error(error)
    }
  }
  handleDeselect = () => {
    this.setState({
      hasElementSelected: false
    })
  }
  handlePropsPanelLeave = () => {
    this.setState({
      elementData: null,
      currentIndex: ''
    })
  }
  handleSiderTransitionEnd = e => {
    if (e.propertyName==='width') {
      const { siderCollapseFlag } = this.state
      this.setState({
        siderCollapseFlag: !siderCollapseFlag
      })
    }
  }
  componentDidMount() {
    this.loadArtboardViewSettings()
  }
  render () {
    const {
      documentName, components, styles, exportSettings, versionData,
      pagedFrames, mode, isMock, includeComponents
    } = this.props
    const {
      id,
      currentImageUrl,
      canvasData,
      exportIds,
      exportNames,
      elementData,
      currentIndex,
      closestComponent,
      hasElementSelected,
      siderCollapseFlag,
      slicePanelVisible,
      artboardViewSettings
    } = this.state
    return (
      <div className="app-main">
        <LeftPanel
          mode={mode}
          isMock={isMock}
          pagedFrames={pagedFrames}
          components={components}
          includeComponents={includeComponents}
          onFrameOrComponentChange={this.handleSelectFrameOrComponent}
          onSiderTransitionEnd={this.handleSiderTransitionEnd}
        />
        {
          canvasData &&
          <Canvas
            currentImageUrl={currentImageUrl}
            canvasData={canvasData}
            id={id}
            elementData={elementData}
            onSelect={this.handleSelectElement}
            onDeselect={this.handleDeselect}
            onGetExports={this.handleGetExports}
            siderCollapseFlag={siderCollapseFlag}
            slicePanelVisible={slicePanelVisible}
            canvasFrames={this.getCanvasFrames()}
            onFrameOrComponentChange={this.handleSelectFrameOrComponent}
            artboardViewSettings={artboardViewSettings}
            onArtboardViewChange={this.handleArtboardViewChange}
            onArtboardViewSave={this.saveArtboardViewSettings}
            onArtboardViewReset={this.resetArtboardViewSettings}
          />
        }
        <RightPanels
          mode={mode}
          isMock={isMock}
          styles={styles}
          exportSettings={exportSettings}
          documentName={documentName}
          elementData={elementData}
          closestComponent={closestComponent}
          currentExportIds={exportIds}
          currentExportNames={exportNames}
          currentIndex={currentIndex}
          versionData={versionData}
          hasElementSelected={hasElementSelected}
          onPropsPanelLeave={this.handlePropsPanelLeave}
          onSiderTransitionEnd={this.handleSiderTransitionEnd}
          onSlicePanelVisibleChange={this.handleSlicePanelVisibleChange}
        />
      </div>
    )
  }
}

export default Main
