import React from 'react'
import lottie from 'lottie-web'
import { Play, Pause, RotateCcw, UploadCloud } from 'react-feather'

class LottiePlayer extends React.Component {
  container = React.createRef()
  fileInput = React.createRef()
  animation = null

  state = {
    fileName: '',
    status: '选择或拖入 Lottie JSON 文件',
    isPlaying: false,
    loop: true,
    speed: 1,
    isDragging: false
  }

  loadAnimation = (animationData, fileName) => {
    if (this.animation) {
      this.animation.destroy()
      this.animation = null
    }
    this.animation = lottie.loadAnimation({
      container: this.container.current,
      renderer: 'svg',
      loop: this.state.loop,
      autoplay: true,
      animationData
    })
    this.animation.setSpeed(this.state.speed)
    this.animation.addEventListener('DOMLoaded', () => {
      this.setState({
        fileName,
        status: '正在播放',
        isPlaying: true
      })
    })
    this.animation.addEventListener('complete', () => {
      if (!this.state.loop) {
        this.setState({ isPlaying: false, status: '播放完成' })
      }
    })
  }

  readFile = file => {
    if (!file) return
    if (!/\.json$/i.test(file.name)) {
      this.setState({ status: '请使用 .json 格式的 Lottie 文件' })
      return
    }
    const reader = new FileReader()
    reader.onload = () => {
      try {
        const data = JSON.parse(reader.result)
        this.loadAnimation(data, file.name)
      } catch (error) {
        this.setState({ status: 'JSON 文件解析失败' })
      }
    }
    reader.readAsText(file)
  }

  handleFileChange = e => {
    this.readFile(e.target.files[0])
    e.target.value = ''
  }

  handleDrop = e => {
    e.preventDefault()
    this.setState({ isDragging: false })
    this.readFile(e.dataTransfer.files[0])
  }

  togglePlay = () => {
    if (!this.animation) return
    if (this.state.isPlaying) {
      this.animation.pause()
      this.setState({ isPlaying: false, status: '已暂停' })
    } else {
      this.animation.play()
      this.setState({ isPlaying: true, status: '正在播放' })
    }
  }

  restart = () => {
    if (!this.animation) return
    this.animation.goToAndPlay(0, true)
    this.setState({ isPlaying: true, status: '正在播放' })
  }

  setLoop = e => {
    const loop = e.target.checked
    if (this.animation) {
      this.animation.loop = loop
    }
    this.setState({ loop })
  }

  setSpeed = e => {
    const speed = Number(e.target.value)
    if (this.animation) {
      this.animation.setSpeed(speed)
    }
    this.setState({ speed })
  }

  componentWillUnmount() {
    if (this.animation) {
      this.animation.destroy()
    }
  }

  render() {
    const { visible } = this.props
    const { fileName, status, isPlaying, loop, speed, isDragging } = this.state
    return (
      <div className={`panel-lottie${visible ? '' : ' hide'}`}>
        <div
          className={`lottie-dropzone${isDragging ? ' is-dragging' : ''}`}
          onDragOver={e => {
            e.preventDefault()
            this.setState({ isDragging: true })
          }}
          onDragLeave={() => this.setState({ isDragging: false })}
          onDrop={this.handleDrop}
        >
          <div className="lottie-stage" ref={this.container}>
            {!fileName && (
              <button className="lottie-empty" onClick={() => this.fileInput.current.click()}>
                <UploadCloud size={22}/>
                <span>选择 Lottie JSON</span>
              </button>
            )}
          </div>
        </div>
        <input ref={this.fileInput} className="hide" type="file" accept=".json,application/json" onChange={this.handleFileChange}/>
        <div className="lottie-info">
          <strong>{fileName || 'Lottie 播放器'}</strong>
          <em>{status}</em>
        </div>
        <div className="lottie-actions">
          <button onClick={() => this.fileInput.current.click()}><UploadCloud size={14}/>选择文件</button>
          <button disabled={!fileName} onClick={this.togglePlay}>{isPlaying ? <Pause size={14}/> : <Play size={14}/>}{isPlaying ? '暂停' : '播放'}</button>
          <button disabled={!fileName} onClick={this.restart}><RotateCcw size={14}/>重播</button>
        </div>
        <label className="lottie-toggle">
          <input type="checkbox" checked={loop} onChange={this.setLoop}/>
          <span>循环播放</span>
        </label>
        <label className="lottie-speed">
          <span>速度</span>
          <input type="range" min="0.25" max="3" step="0.25" value={speed} onChange={this.setSpeed}/>
          <em>{speed}x</em>
        </label>
      </div>
    )
  }
}

export default LottiePlayer
